import{_ as a,o as r,c as t,ak as p}from"./chunks/framework.DsiwUQoa.js";const h=JSON.parse('{"title":"我其实知道的","description":"","frontmatter":{},"headers":[],"relativePath":"Note/我其实知道/index.md","filePath":"Note/我其实知道/index.md"}'),s={name:"Note/我其实知道/index.md"};function n(i,e,o,d,c,l){return r(),t("div",null,[...e[0]||(e[0]=[p('<h1 id="我其实知道的" tabindex="-1">我其实知道的 <a class="header-anchor" href="#我其实知道的" aria-label="Permalink to “我其实知道的”">​</a></h1><p>你在进入这个网站的时候，你也许会想——</p><h3 id="这个网站有什么用" tabindex="-1">这个网站有什么用？ <a class="header-anchor" href="#这个网站有什么用" aria-label="Permalink to “这个网站有什么用？”">​</a></h3><h3 id="何意味" tabindex="-1">何意味？ <a class="header-anchor" href="#何意味" aria-label="Permalink to “何意味？”">​</a></h3><p>其实，这个网站，没有任何作用</p><p>我不需要让你知道这个网站的用处</p><p>因为这个网站，其实是为了满足我小时候的一个愿望——</p><p>我在很小的时候就希望我有一个网站，那时我还只会用Canva来弄个带许多超链接的项目，然后分享为网址。而现在长大了，我认识到了NodeJS、React、VitePress、Markdown……我就用VitePress搭配GitHubActions来搭建一个我小时候觉得搭建起来超难的网站。</p><p>而我，也知道这个网站没有用</p><p>但是，也正因如此，在这个网站，我也能继续当User</p><p>我不想把自己包装成一个黑客、技术大神……至少，我自己不喜欢。</p><p>因为我自己也是一名User，所以我不会用这个网站赚钱，也不会用这个网站去恶心其他的User，因为我觉得，这样对不起我自己</p><p>所以，我不可能把我的网站也变成那样</p><p>我不需要挣钱，也不需要恶心其他和我一样的User，因为我也是User</p>',14)])])}const m=a(s,[["render",n]]);export{h as __pageData,m as default};
